+/// Execute a plugin subprocess with stdin/stdout JSON protocol.
+///
+/// Returns the stdout bytes and execution duration on success,
+/// or an error message string on failure.
+fn invoke_subprocess(
+    command: &Path,
+    args: &[String],
+    working_dir: &Path,
+    stdin_data: &[u8],
+    timeout_ms: u64,
+    max_output: usize,
+) -> Result<(Vec<u8>, Duration), String> {
+    let start = Instant::now();
+
+    let mut child = Command::new(command)
+        .args(args)
+        .current_dir(working_dir)
+        .stdin(Stdio::piped())
+        .stdout(Stdio::piped())
+        .stderr(Stdio::piped())
+        .spawn()
+        .map_err(|e| format!("failed to spawn: {e}"))?;
+
+    // Write stdin
+    if let Some(mut stdin) = child.stdin.take() {
+        stdin
+            .write_all(stdin_data)
+            .map_err(|e| format!("failed to write stdin: {e}"))?;
+        // stdin is dropped here, closing the pipe
+    }
+
+    // Wait with timeout
+    let timeout = Duration::from_millis(timeout_ms);
+    let output = match child.wait_with_output() {
+        Ok(output) => {
+            let elapsed = start.elapsed();
+            if elapsed > timeout {
+                return Err(format!("timed out after {}ms", elapsed.as_millis()));
+            }
+            output
+        }
+        Err(e) => return Err(format!("wait failed: {e}")),
+    };
+
+    let duration = start.elapsed();
+
+    if !output.status.success() {
+        let stderr = String::from_utf8_lossy(&output.stderr);
+        let code = output.status.code().unwrap_or(-1);
+        return Err(format!(
+            "exited with code {code}: {}",
+            stderr.chars().take(500).collect::<String>()
+        ));
+    }
+
+    let mut stdout = output.stdout;
+    if stdout.len() > max_output {
+        stdout.truncate(max_output);
+        warn!(
+            "plugin output truncated from {} to {} bytes",
+            stdout.len(),
+            max_output
+        );
+    }
+
+    Ok((stdout, duration))
+}
